mapper.select:
select e.id, e.username, e.name, e.gender, e.phone, e.salary, e.dept_id as deptId, d.name as deptName, e.position, e.entry_date as entryDate, e.image, e.create_time as createTime, e.update_time as updateTime from emp e left join dept d on e.dept_id = d.id
and e.name like concat('%', #{name}, '%')
and e.gender = #{gender}
and e.entry_date >= #{beginDate}
and e.entry_date <= #{endDate}
order by e.update_time desc

